 37â†’// NewStorage returns a new in memory Storage base.
 38â†’func NewStorage(o ...StorageOption) *Storage {
 39â†’	opts := newOptions()
 40â†’	for _, opt := range o {
 41â†’		opt(&opts)
 42â†’	}
 43â†’
 44â†’	s := &Storage{
 45â†’		options:          opts,
 46â†’		ReferenceStorage: make(ReferenceStorage),
 47â†’		ConfigStorage:    ConfigStorage{},
 48â†’		ShallowStorage:   ShallowStorage{},
 49â†’		ObjectStorage: ObjectStorage{
 50â†’			Objects: make(map[plumbing.Hash]plumbing.EncodedObject),
 51â†’			Commits: make(map[plumbing.Hash]plumbing.EncodedObject),
 52â†’			Trees:   make(map[plumbing.Hash]plumbing.EncodedObject),
 53â†’			Blobs:   make(map[plumbing.Hash]plumbing.EncodedObject),
 54â†’			Tags:    make(map[plumbing.Hash]plumbing.EncodedObject),
 55â†’		},
 56â†’		ModuleStorage: make(ModuleStorage),
 57â†’	}
 58â†’
 59â†’	if opts.objectFormat != formatcfg.UnsetObjectFormat {
 60â†’		cfg, _ := s.Config()
 61â†’		cfg.Extensions.ObjectFormat = opts.objectFormat
 62â†’		cfg.Core.RepositoryFormatVersion = formatcfg.Version1
 63â†’		s.oh = plumbing.FromObjectFormat(opts.objectFormat)
 64â†’	} else {
 65â†’		s.oh = plumbing.FromObjectFormat(formatcfg.DefaultObjectFormat)
 66â†’	}
 67â†’
 68â†’	return s
 69â†’}
