 71â†’func (s *Storage) SetObjectFormat(of formatcfg.ObjectFormat) error {
 72â†’	switch of {
 73â†’	case formatcfg.SHA1, formatcfg.SHA256:
 74â†’	default:
 75â†’		return fmt.Errorf("invalid object format: %s", of)
 76â†’	}
 77â†’
 78â†’	// Presently, storage only supports a single object format at a
 79â†’	// time. Changing the format of an existing (and populated) object
 80â†’	// storage is yet to be supported.
 81â†’	if len(s.Blobs) > 0 ||
 82â†’		len(s.Commits) > 0 ||
 83â†’		len(s.Objects) > 0 ||
 84â†’		len(s.Tags) > 0 ||
 85â†’		len(s.Trees) > 0 {
 86â†’		return errors.New("cannot change object format of existing object storage")
 87â†’	}
 88â†’
 89â†’	if s.options.objectFormat == of {
 90â†’		return nil
 91â†’	}
 92â†’
 93â†’	cfg, _ := s.Config()
 94â†’	cfg.Extensions.ObjectFormat = of
 95â†’	cfg.Core.RepositoryFormatVersion = formatcfg.Version1
 96â†’	s.options.objectFormat = of
