package filesystem

import (
	"bufio"
	"hash"
	"os"
	"sync"
	"time"

	"github.com/go-git/go-git/v6/plumbing/format/index"
	"github.com/go-git/go-git/v6/storage/filesystem/dotgit"
	"github.com/go-git/go-git/v6/utils/ioutil"
	"github.com/go-git/go-git/v6/utils/trace"
)

type IndexStorage struct {
	dir *dotgit.DotGit
	h   hash.Hash

	mu       sync.RWMutex
	cached   *index.Index
	modTime  time.Time
	fileSize int64
}

func (s *IndexStorage) SetIndex(idx *index.Index) (err error) {
	f, err := s.dir.IndexWriter()
	if err != nil {
		return err
	}

	defer ioutil.CheckClose(f, &err)
	bw := bufio.NewWriter(f)
	defer func() {
		if e := bw.Flush(); err == nil && e != nil {
			err = e
		}
	}()

	e := index.NewEncoder(bw, s.h)
	err = e.Encode(idx)
	if err != nil {
		return err
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	fi, statErr := s.dir.StatIndex()
	if statErr == nil {
		s.cached = idx
		s.modTime = fi.ModTime()
		s.fileSize = fi.Size()
	} else {
		// Stat failed after a successful write; clear cache to be safe.
		s.cached = nil
	}

	return nil
}

func (s *IndexStorage) Index() (i *index.Index, err error) {
	if trace.Performance.Enabled() {
		start := time.Now()
		defer func() {
			trace.Performance.Printf("performance: %.9f s: storage/filesystem: get index()", time.Since(start).Seconds())
		}()
	}

	fi, statErr := s.dir.StatIndex()
	if statErr != nil {
		if os.IsNotExist(statErr) {
			s.mu.Lock()
			s.cached = nil
			s.mu.Unlock()
			return &index.Index{Version: 2}, nil
		}
		return nil, statErr
	}

	s.mu.RLock()
	if s.cached != nil && fi.ModTime().Equal(s.modTime) && fi.Size() == s.fileSize {
		idx := *s.cached
		s.mu.RUnlock()
		return &idx, nil
	}
	s.mu.RUnlock()

	idx := &index.Index{
		Version: 2,
	}

	f, err := s.dir.Index()
	if err != nil {
		if os.IsNotExist(err) {
			return idx, nil
		}
		return nil, err
	}

	defer ioutil.CheckClose(f, &err)

	fileFi, err := f.Stat()
	if err == nil {
		idx.ModTime = fileFi.ModTime()
	}

	d := index.NewDecoder(f, s.h)
	err = d.Decode(idx)
	if err != nil {
		return nil, err
	}

	s.mu.Lock()
	s.cached = idx
	s.modTime = fi.ModTime()
	s.fileSize = fi.Size()
	s.mu.Unlock()

	cp := *idx
	return &cp, nil
}

