	t.Parallel()
	sto := newIndexStorage(t)

	orig := &index.Index{
		Version: 2,
		Entries: []*index.Entry{
			{Hash: plumbing.NewHash("880cd14280f4b9b6ed3986d6671f907d7cc2a198"), Name: "foo.go"},
		},
	}
	require.NoError(t, sto.SetIndex(orig))

	idx1, err := sto.Index()
	require.NoError(t, err)

