	_, err := sto.Index()
	require.NoError(t, err)

	// Delete the index file externally.
	require.NoError(t, os.Remove(tmp+"/index"))

	// Should return empty v2 index and clear cache.
	got, err := sto.Index()
	require.NoError(t, err)
	assert.Equal(t, uint32(2), got.Version)
	assert.Empty(t, got.Entries)
}

