package filesystem

import (
	"bufio"
	"errors"
	"hash"
	"os"
	"time"

	"github.com/go-git/go-git/v6/plumbing/format/index"
	"github.com/go-git/go-git/v6/storage/filesystem/dotgit"
	"github.com/go-git/go-git/v6/utils/ioutil"
	"github.com/go-git/go-git/v6/utils/trace"
)

type IndexStorage struct {
	dir   *dotgit.DotGit
	h     hash.Hash
	cache IndexCache
}

func (s *IndexStorage) SetIndex(idx *index.Index) (err error) {
	if err := s.writeIndex(idx); err != nil {
		return err
	}

	if s.cache != nil {
		fi, statErr := s.dir.StatIndex()
		if statErr == nil {
			s.cache.Set(idx, fi.ModTime(), fi.Size())
		} else {
			s.cache.Clear()
		}
	}

	return nil
}

func (s *IndexStorage) writeIndex(idx *index.Index) (err error) {
	f, err := s.dir.IndexWriter()
	if err != nil {
		return err
	}

	defer ioutil.CheckClose(f, &err)
	bw := bufio.NewWriter(f)
	defer func() {
		if e := bw.Flush(); err == nil && e != nil {
			err = e
		}
	}()

	e := index.NewEncoder(bw, s.h)
	return e.Encode(idx)
}

func (s *IndexStorage) Index() (i *index.Index, err error) {
	if trace.Performance.Enabled() {
		start := time.Now()
		defer func() {
			trace.Performance.Printf("performance: %.9f s: storage/filesystem: get index()", time.Since(start).Seconds())
		}()
	}

	if s.cache != nil {
		fi, err := s.dir.StatIndex()
		if err != nil {
			if errors.Is(err, os.ErrNotExist) {
				s.cache.Clear()
				return &index.Index{Version: 2}, nil
			}
			return nil, err
		}

		if cached := s.cache.Get(fi.ModTime(), fi.Size()); cached != nil {
			cp := *cached
			return &cp, nil
		}
	}

	idx := &index.Index{
		Version: 2,
	}

	f, err := s.dir.Index()
	if err != nil {
		if errors.Is(err, os.ErrNotExist) {
			return idx, nil
		}
		return nil, err
	}

	defer ioutil.CheckClose(f, &err)

	fi, err := f.Stat()
	if err == nil {
		idx.ModTime = fi.ModTime()
	}

	d := index.NewDecoder(f, s.h)
	err = d.Decode(idx)
	if err != nil {
		return nil, err
	}

	if s.cache != nil {
		s.cache.Set(idx, fi.ModTime(), fi.Size())
	}

	cp := *idx
	return &cp, nil
}

